def transition(state: dict, action: dict) -> dict:
    next_state = state.copy()

    if action['name'] == 'ship':
        if state['backlog'] > 0:
            next_state['backlog'] -= 1
            next_state['shipped'] += 1
            next_state['debt'] += 1
            bugs_increase = next_state['debt'] // 4
            next_state['bugs'] += max(0, bugs_increase)

    elif action['name'] == 'fix':
        next_state['bugs'] = max(0, next_state['bugs'] - 2)

    elif action['name'] == 'refactor':
        next_state['debt'] = max(0, next_state['debt'] - 2)

    return next_state
